parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "match_found": {
      "type": "boolean",
      "description": "Indicates whether a relevant reference playbook was identified."
    },
    "playbook_id": {
      "type": ["string", "null"],
      "description": "UUID of the selected playbook. Null if no match."
    },
    "playbook_name": {
      "type": ["string", "null"],
      "description": "Exact name of the selected playbook. Null if no match."
    },
    "confidence": {
      "type": "string",
      "enum": ["high", "medium", "low"]
    },
    "reasoning": {
      "type": "string"
    }
  },
  "required": [
    "match_found",
    "playbook_id",
    "playbook_name",
    "confidence",
    "reasoning"
  ],
  "additionalProperties": false
}

{
  "type": "object",
  "properties": {
    "incident_classification": {
      "type": "string",
      "enum": [
        "SECURITY_ATTACK",
        "SECURITY_VULNERABILITY",
        "CLOUD_SECURITY",
        "POLICY_VIOLATION",
        "AVAILABILITY",
        "PERFORMANCE"
      ],
      "description": "Incident type classification determined in Step 1. Controls search behavior."
    },
    "external_research_used": {
      "type": "boolean",
      "description": "Indicates whether external research was performed."
    },
    "threat_intelligence": {
      "type": "array",
      "maxItems": 6,
      "description": "Structured findings from CVEs, advisories, campaigns, or known issues. Maximum 6 items.",
      "items": {
        "type": "object",
        "properties": {
          "category": {
            "type": "string",
            "enum": [
              "CVE",
              "Vendor Advisory",
              "Active Campaign",
              "Known Issue",
              "Exploit Activity"
            ],
            "description": "CVE only for real CVE-YYYY-NNNNN IDs. Active Campaign for named threat actors."
          },
          "title": { "type": "string" },
          "summary": {
            "type": "string",
            "description": "Max 3 sentences. Concise and technical. No narrative paragraphs."
          },
          "affected_products": { "type": ["string", "null"] },
          "affected_versions": { "type": ["string", "null"] },
          "severity": { "type": ["string", "null"] },
          "exploitation_status": {
            "type": ["string", "null"],
            "enum": ["active", "proof_of_concept", "theoretical", null]
          },
          "source_name": { "type": "string" },
          "source_url": { "type": "string" },
          "published_date": {
            "type": ["string", "null"],
            "description": "ISO-8601 YYYY-MM-DD or YYYY-MM only. Never year-only strings like '2025'. Use null if month unknown."
          },
          "applicability_confidence": {
            "type": "string",
            "enum": ["high", "medium", "low"],
            "description": "How directly this finding relates to the incident. high=exact product match or directly referenced. medium=same product family or technique class. low=general context only."
          },
          "applicability_notes": {
            "type": ["string", "null"],
            "description": "Required when applicability_confidence is medium or low. Explain the relevance connection."
          }
        },
        "required": [
          "category",
          "title",
          "summary",
          "source_name",
          "source_url",
          "applicability_confidence"
        ],
        "additionalProperties": false
      }
    },
    "ioc_indicators": {
      "type": "array",
      "description": "Concrete, specific indicators of compromise extracted from research. Empty array if none found.",
      "items": {
        "type": "object",
        "properties": {
          "type": {
            "type": "string",
            "enum": [
              "file_hash",
              "ip_address",
              "domain",
              "registry_key",
              "process_name",
              "file_extension",
              "port",
              "command_pattern",
              "filename"
            ]
          },
          "value": { "type": "string" },
          "context": {
            "type": "string",
            "description": "What this IOC represents (e.g., 'TamperedChef info-stealer persistence registry key')"
          },
          "source_url": { "type": "string" }
        },
        "required": ["type", "value", "context", "source_url"],
        "additionalProperties": false
      }
    },
    "mitigation_guidance": {
      "type": "array",
      "maxItems": 6,
      "description": "Phase-labeled, actionable remediation steps. Maximum 6. Prioritize IMMEDIATE and CONTAINMENT.",
      "items": {
        "type": "object",
        "properties": {
          "phase": {
            "type": "string",
            "enum": [
              "IMMEDIATE",
              "CONTAINMENT",
              "DETECTION",
              "INVESTIGATION",
              "HARDENING",
              "RECOVERY"
            ],
            "description": "IMMEDIATE=act within 15min. CONTAINMENT=stop spread. DETECTION=identify scope. INVESTIGATION=root cause. HARDENING=prevent recurrence. RECOVERY=restore service."
          },
          "action": {
            "type": "string",
            "description": "Specific, actionable step. Include exact commands, paths, query strings, or API calls where available."
          },
          "source_name": { "type": ["string", "null"] },
          "source_url": { "type": ["string", "null"] }
        },
        "required": ["phase", "action"],
        "additionalProperties": false
      }
    },
    "emerging_risk_assessment": {
      "type": "object",
      "properties": {
        "active_exploitation_observed": {
          "type": ["boolean", "null"],
          "description": "true only if exploitation_status=active AND threat is directly relevant to this specific incident type. Not true for unrelated active campaigns."
        },
        "risk_trend": {
          "type": "string",
          "enum": ["increasing", "stable", "decreasing", "unknown"]
        },
        "confidence": {
          "type": "string",
          "enum": ["high", "medium", "low"]
        },
        "notes": {
          "type": "string",
          "description": "Max 4 sentences. Summarize threat landscape context and incident-specific risk factors."
        }
      },
      "required": [
        "active_exploitation_observed",
        "risk_trend",
        "confidence",
        "notes"
      ],
      "additionalProperties": false
    },
    "sources_consulted": {
      "type": "array",
      "description": "MUST ONLY contain URLs that appear as source_url in threat_intelligence or mitigation_guidance. No additional URLs.",
      "items": { "type": "string" }
    },
    "overall_confidence": {
      "type": "string",
      "enum": ["high", "medium", "low"]
    }
  },
  "required": [
    "incident_classification",
    "external_research_used",
    "threat_intelligence",
    "ioc_indicators",
    "mitigation_guidance",
    "emerging_risk_assessment",
    "sources_consulted",
    "overall_confidence"
  ],
  "additionalProperties": false
}

